123→```rust
124→/// Detects significant price changes since the last tick.
125→///
126→/// A large price delta indicates either an opportunity (potential trade)
127→/// or a threat (position health deterioration). The threshold is
128→/// calibrated per-asset based on historical volatility.
129→pub struct PriceDeltaProbe {
130→    /// Per-asset volatility-normalized thresholds
131→    thresholds: HashMap<AssetId, f32>,
132→}
133→
134→impl Probe for PriceDeltaProbe {
135→    fn evaluate(&self, state: &EngineState) -> f32 {
136→        let max_delta = state.tracked_assets()
137→            .iter()
138→            .map(|asset| {
139→                let delta = (asset.current_price - asset.last_tick_price).abs()
140→                    / asset.last_tick_price;
141→                let threshold = self.thresholds.get(&asset.id)
142→                    .copied()
143→                    .unwrap_or(0.02);  // 2% default
144→                (delta / threshold).min(1.0)
145→            })
146→            .fold(0.0f32, f32::max);
147→        max_delta
148→    }
149→
150→    fn weight(&self) -> f32 { 0.15 }
151→    fn name(&self) -> &str { "price_delta" }
152→    fn domain(&self) -> ProbeDomain { ProbeDomain::Chain }
153→}
