340→        match state.last_build_result() {
341→            BuildResult::Success => 0.0,
342→            BuildResult::Warning(count) => (count as f32 * 0.1).min(0.5),
343→            BuildResult::Failure => 0.8,
344→            BuildResult::Unknown => 0.3,  // No recent build data
345→        }
346→    }
347→
348→    fn weight(&self) -> f32 { 0.20 }
349→    fn name(&self) -> &str { "build_health" }
350→    fn domain(&self) -> ProbeDomain { ProbeDomain::Coding }
351→}
352→```
353→
354→#### Probe 10: Test Regression
355→
356→Detects changes in test count since the last run. A decrease in passing tests indicates regression.
357→
358→```rust
359→pub struct TestRegressionProbe;
360→
361→impl Probe for TestRegressionProbe {
362→    fn evaluate(&self, state: &EngineState) -> f32 {
363→        let delta = state.test_pass_count_delta();
364→        if delta < 0 {
365→            ((-delta) as f32 * 0.2).min(1.0)  // Each failing test: 0.2
366→        } else {
367→            0.0
368→        }
369→    }
370→
371→    fn weight(&self) -> f32 { 0.20 }
372→    fn name(&self) -> &str { "test_regression" }
373→    fn domain(&self) -> ProbeDomain { ProbeDomain::Coding }
374→}
375→```
376→
377→#### Probe 11: Complexity Drift
378→
379→Monitors cyclomatic complexity moving average. Increasing complexity may indicate code quality degradation.
380→
381→```rust
382→pub struct ComplexityDriftProbe;
383→
384→impl Probe for ComplexityDriftProbe {
385→    fn evaluate(&self, state: &EngineState) -> f32 {
386→        let drift = state.complexity_delta_percent();
387→        (drift / 10.0).clamp(0.0, 1.0)  // 10% complexity increase = maximum
388→    }
389→
390→    fn weight(&self) -> f32 { 0.05 }
391→    fn name(&self) -> &str { "complexity_drift" }
392→    fn domain(&self) -> ProbeDomain { ProbeDomain::Coding }
393→}
394→```
395→
396→#### Probe 12: Dependency Risk
397→
398→Monitors vulnerability scan results for dependency changes.
399→
400→```rust
401→pub struct DependencyRiskProbe;
402→
403→impl Probe for DependencyRiskProbe {
404→    fn evaluate(&self, state: &EngineState) -> f32 {
405→        let new_vulns = state.new_vulnerability_count();
406→        match new_vulns {
407→            0 => 0.0,
408→            1..=2 => 0.4,
409→            3..=5 => 0.7,
410→            _ => 1.0,
411→        }
412→    }
413→
414→    fn weight(&self) -> f32 { 0.10 }
415→    fn name(&self) -> &str { "dependency_risk" }
416→    fn domain(&self) -> ProbeDomain { ProbeDomain::Coding }
417→}
418→```
419→
420→#### Probe 13: Coverage Delta
421→
422→Monitors test coverage changes. A significant drop in coverage may indicate untested new code.
423→
424→```rust
