427→impl Probe for CoverageDeltaProbe {
428→    fn evaluate(&self, state: &EngineState) -> f32 {
429→        let delta = state.coverage_delta_percent();
430→        if delta < -2.0 {
431→            ((-delta) / 10.0).min(1.0)  // 10% coverage drop = maximum
432→        } else {
