480→    fn evaluate(&self, state: &EngineState) -> f32 {
481→        let predicted = state.predicted_state_vector();
482→        let actual = state.actual_state_vector();
483→        let drift = cosine_distance(&predicted, &actual);
484→        drift.clamp(0.0, 1.0)
485→    }
486→
487→    fn weight(&self) -> f32 { 0.15 }
488→    fn name(&self) -> &str { "world_model_drift" }
489→    fn domain(&self) -> ProbeDomain { ProbeDomain::Universal }
490→}
491→```
492→
493→#### Probe 16: Causal Consistency
494→
495→Checks the integrity of the lineage DAG. Detects missing parents, hash mismatches, or orphaned Engrams that could indicate corruption or tampering.
496→
