 56→// ─── CascadeStage ───────────────────────────────────────────────────────────
 57→
 58→/// Which routing stage is currently active.
 59→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
 60→pub enum CascadeStage {
 61→    /// Stage 1: hardcoded role -> model table (< 50 observations).
 62→    Static,
 63→    /// Stage 2: empirical pass rates with confidence interval (50-200 observations).
 64→    Confidence,
 65→    /// Stage 3: full `LinUCB` contextual bandit (> 200 observations).
 66→    Ucb,
 67→}
 68→
 69→impl CascadeStage {
 70→    /// Human-readable label.
 71→    #[must_use]
 72→    pub const fn label(self) -> &'static str {
 73→        match self {
 74→            Self::Static => "static",
 75→            Self::Confidence => "confidence",
 76→            Self::Ucb => "ucb",
 77→        }
 78→    }
 79→}
 80→
 81→impl std::fmt::Display for CascadeStage {
 82→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 83→        f.write_str(self.label())
 84→    }
 85→}
 86→
 87→/// Recorded transition between cascade maturity stages.
 88→#[derive(Debug, Clone, PartialEq, Eq, Serialize, Deserialize)]
 89→pub struct StageTransition {
 90→    /// Previous active stage.
 91→    pub from: CascadeStage,
 92→    /// Newly activated stage.
 93→    pub to: CascadeStage,
 94→    /// Observation count when the transition occurred.
 95→    pub observations: u64,
 96→    /// Timestamp when the transition was recorded.
 97→    pub timestamp: DateTime<Utc>,
 98→}
 99→
100→// ─── CascadeModel ───────────────────────────────────────────────────────────
101→
102→/// Routing recommendation from the cascade.
103→#[derive(Debug, Clone)]
104→pub struct CascadeModel {
105→    /// Primary model to use.
106→    pub primary: ModelSpec,
107→    /// Ordered fallback models to try after general failures.
108→    pub fallback_chain: Vec<ModelSpec>,
109→    /// Larger-context model to try when the primary overflows context.
110→    pub context_overflow_fallback: Option<ModelSpec>,
111→    /// Latency SLA in milliseconds.
112→    pub latency_sla_ms: u64,
113→    /// Which cascade stage produced this recommendation.
114→    pub stage: CascadeStage,
115→}
116→
117→impl CascadeModel {
118→    /// Return the model to use for the given attempt number.
119→    ///
120→    /// Attempt 0 is the primary model. Subsequent attempts walk the fallback
121→    /// chain in order until it is exhausted.
122→    #[must_use]
123→    pub fn model_for_attempt(&self, attempt: usize) -> Option<&ModelSpec> {
124→        match attempt {
125→            0 => Some(&self.primary),
126→            _ => self.fallback_chain.get(attempt - 1),
127→        }
128→    }
129→
130→    /// Return the best fallback to use for a provider-specific failure.
131→    #[must_use]
132→    pub fn fallback_for_error(&self, error: &ProviderError) -> Option<&ModelSpec> {
133→        match error {
134→            ProviderError::ContextOverflow => self.context_overflow_fallback.as_ref(),
135→            ProviderError::RateLimit { .. } => self
136→                .fallback_chain
137→                .iter()
138→                .find(|model| model.backend != self.primary.backend)
139→                .or_else(|| self.fallback_chain.first()),
140→            _ => self.fallback_chain.first(),
141→        }
142→    }
143→}
