  1→//! `TaskMetric` — the raw data foundation for Roko's continuous-tuning loops.
  2→//!
  3→//! Every gate verdict produces one [`TaskMetric`] record. Records are appended
  4→//! to `.roko/runs/{run_id}/metrics.jsonl` by the persistence layer
  5→//! (`roko-fs::metrics::MetricsLog`) and consumed by the five optimization
  6→//! loops described in `tmp/roko-progress/roko-continuous-tuning.md`.
  7→//!
  8→//! The join key across every record is [`ConfigHash`]: a 16-char BLAKE3
  9→//! prefix of the run's canonical `RokoConfig`. All analysis slices by
 10→//! `config_hash` — that is the primitive operation that makes all five
 11→//! loops work.
 12→//!
 13→//! # Discipline
 14→//!
 15→//! Three rules for this layer, from §1 of `roko-continuous-tuning.md`:
 16→//!
 17→//! 1. **Ship this first.** No loop is worth anything without clean metric
 18→//!    data. Get `TaskMetric` emitting on every gate before starting any
 19→//!    optimizer.
 20→//! 2. **Record 20+ plans before drawing conclusions.** Then compute the
 21→//!    four headline metrics via [`compute_headlines`]. That is your
 22→//!    baseline.
 23→//! 3. **Never mutate records.** Metrics are immutable; `.jsonl` is
 24→//!    append-only. Bad data stays and is filtered, never rewritten.
 25→
 26→use serde::{Deserialize, Serialize};
 27→
 28→/// 16-char BLAKE3 prefix over a canonical-JSON-serialized config.
 29→///
 30→/// Stable across machines (no timestamps, no process-specific state in
 31→/// the hash input). This is the **join key** across every `TaskMetric`
 32→/// record — all analysis compares configs by their hash.
 33→#[derive(Debug, Clone, PartialEq, Eq, Hash, Serialize, Deserialize)]
 34→pub struct ConfigHash(pub String);
 35→
 36→impl ConfigHash {
 37→    /// Compute the hash of any serializable value.
 38→    ///
 39→    /// The input is first serialized to **canonical JSON** (sorted keys,
 40→    /// no whitespace variability), then BLAKE3-hashed, then the first
 41→    /// 8 bytes are hex-encoded giving a 16-char string.
 42→    ///
 43→    /// # Errors
 44→    ///
 45→    /// Returns an error if the value cannot be serialized to JSON. In
 46→    /// practice this only happens for types with custom serializers
 47→    /// that fail — plain config structs never fail.
 48→    pub fn of<T: Serialize>(value: &T) -> Result<Self, serde_json::Error> {
 49→        // Round-trip through serde_json::Value to get deterministic key
 50→        // ordering. serde_json::to_string alone preserves struct-field
 51→        // order, but fails for HashMap<String, _>. Going through Value
 52→        // and then re-serializing with sort_keys gives a canonical form.
 53→        let v = serde_json::to_value(value)?;
 54→        let canonical = canonical_json(&v);
 55→        let digest = blake3::hash(canonical.as_bytes());
 56→        let bytes = digest.as_bytes();
 57→        let hex = hex_prefix(&bytes[..8]);
 58→        Ok(Self(hex))
 59→    }
 60→
 61→    /// Borrow the inner 16-char hex string.
 62→    #[must_use]
 63→    pub fn as_str(&self) -> &str {
 64→        &self.0
 65→    }
 66→}
 67→
 68→impl std::fmt::Display for ConfigHash {
 69→    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
 70→        f.write_str(&self.0)
 71→    }
 72→}
 73→
 74→impl From<String> for ConfigHash {
 75→    fn from(s: String) -> Self {
 76→        Self(s)
 77→    }
 78→}
 79→
 80→/// Render bytes as a hex-encoded string.
 81→fn hex_prefix(bytes: &[u8]) -> String {
 82→    let mut s = String::with_capacity(bytes.len() * 2);
 83→    for b in bytes {
 84→        use std::fmt::Write;
 85→        let _ = write!(s, "{b:02x}");
 86→    }
 87→    s
 88→}
 89→
 90→/// Serialize a `serde_json::Value` with sorted object keys.
 91→///
 92→/// `serde_json` preserves insertion order for `Map<String, Value>`
 93→/// (since it uses a `BTreeMap` by default — wait, it uses `BTreeMap`
 94→/// ONLY with the `preserve_order` feature **off**). We guarantee sort
 95→/// order regardless by walking the value and rebuilding with a sorted
 96→/// `BTreeMap`.
 97→fn canonical_json(v: &serde_json::Value) -> String {
 98→    use serde_json::Value;
 99→    fn walk(v: &Value, out: &mut String) {
100→        match v {
101→            Value::Null => out.push_str("null"),
102→            Value::Bool(b) => out.push_str(if *b { "true" } else { "false" }),
103→            Value::Number(n) => out.push_str(&n.to_string()),
104→            Value::String(s) => {
105→                // serde_json handles escaping — cheapest to call it.
106→                out.push_str(&serde_json::to_string(s).unwrap_or_else(|_| "\"\"".into()));
107→            }
108→            Value::Array(arr) => {
109→                out.push('[');
110→                for (i, item) in arr.iter().enumerate() {
111→                    if i > 0 {
112→                        out.push(',');
113→                    }
114→                    walk(item, out);
115→                }
116→                out.push(']');
117→            }
118→            Value::Object(map) => {
119→                let mut keys: Vec<&String> = map.keys().collect();
120→                keys.sort();
121→                out.push('{');
122→                for (i, k) in keys.iter().enumerate() {
123→                    if i > 0 {
124→                        out.push(',');
125→                    }
126→                    out.push_str(&serde_json::to_string(k).unwrap_or_else(|_| "\"\"".into()));
127→                    out.push(':');
128→                    walk(&map[*k], out);
129→                }
130→                out.push('}');
131→            }
132→        }
133→    }
134→    let mut s = String::new();
135→    walk(v, &mut s);
136→    s
137→}
138→
139→/// One record per gate execution. Serialized as a line of `JSONL`.
140→///
141→/// Mirrors §1.1 of `roko-continuous-tuning.md`. All five tuning loops
142→/// slice this table by `config_hash` (the join key) + some subset of
143→/// `role`/`complexity_band`/`gate`.
144→#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
145→pub struct TaskMetric {
146→    // ── Identity ─────────────────────────────────────────────────
147→    /// ISO-8601 UTC timestamp when the gate completed.
148→    pub timestamp: String,
149→    /// Git SHA of the Roko binary that produced this record.
150→    pub run_id: String,
151→    /// The join key — which `RokoConfig` produced this record.
152→    pub config_hash: ConfigHash,
153→    /// Plan this task belongs to (e.g. `"46-reputation-engine"`).
154→    pub plan_id: String,
155→    /// Task within the plan (e.g. `"t3"`).
156→    pub task_id: String,
157→    /// Iteration number (1 = first attempt).
158→    pub iteration: u32,
159→
160→    // ── Routing ──────────────────────────────────────────────────
