176→    pub wall_time_ms: u64,
177→
178→    // ── Cost ─────────────────────────────────────────────────────
179→    /// LLM input tokens for the agent turn(s) this gate verified.
180→    pub input_tokens: u64,
181→    /// LLM output tokens.
182→    pub output_tokens: u64,
183→    /// Tokens served from the prefix cache (subset of input).
184→    pub cached_tokens: u64,
185→    /// Cost in USD for this task's LLM spend.
186→    pub cost_usd: f64,
187→
188→    // ── Context shape ────────────────────────────────────────────
189→    /// Number of sections included in the final prompt.
190→    pub sections_included: u32,
191→    /// Number of sections dropped by budget pressure.
192→    pub sections_dropped: u32,
193→    /// Total tokens in the final assembled prompt.
194→    pub context_tokens: u64,
195→    /// Fraction of input tokens that hit the prefix cache (`cached/input`).
196→    pub cache_hit_rate: f64,
