252→/// The four headline metrics (§1.1 of `roko-continuous-tuning.md`).
253→///
254→/// Computed from a slice of [`TaskMetric`] records. These are the
255→/// numbers every tuning loop optimizes against — no loop should
256→/// introduce a fifth objective.
257→#[derive(Debug, Clone, Copy, PartialEq, Serialize, Deserialize)]
258→pub struct Headlines {
259→    /// Fraction of first-attempt gate runs that passed (`[0..1]`).
260→    ///
261→    /// This is **the** headline number. Improvements here are usually
262→    /// real; regressions usually cost real money.
263→    pub first_attempt_pass_rate: f64,
264→    /// Average number of iterations per plan (max iteration observed).
265→    ///
266→    /// Cost multiplier: if a plan needs 3 iterations, the LLM spend is
267→    /// ≈3× the baseline.
268→    pub avg_iterations_per_plan: f64,
269→    /// Average USD spent per plan.
270→    pub avg_cost_per_plan: f64,
271→    /// Average input tokens per gate record (proxy for prompt size).
272→    pub avg_input_tokens_per_spawn: f64,
273→    /// Number of distinct plans contributing to these numbers.
274→    pub n_plans: usize,
275→    /// Number of records (gate executions) contributing.
276→    pub n_records: usize,
277→}
278→
279→/// Compute the four headline metrics over a slice of records.
280→///
281→/// Mirrors the Python reference in §1.1:
282→/// - `first_attempt_pass_rate`: mean of `gate_passed` over records with `iteration == 1`
283→/// - `avg_iterations_per_plan`: mean of `max(iteration)` per `plan_id`
284→/// - `avg_cost_per_plan`: mean of `sum(cost_usd)` per `plan_id`
285→/// - `avg_input_tokens_per_spawn`: mean of `input_tokens` over all records
286→///
287→/// Returns a [`Headlines`] with zeros in all fields if `records` is empty.
288→#[must_use]
289→#[allow(clippy::cast_precision_loss)]
290→pub fn compute_headlines(records: &[TaskMetric]) -> Headlines {
291→    if records.is_empty() {
292→        return Headlines {
293→            first_attempt_pass_rate: 0.0,
294→            avg_iterations_per_plan: 0.0,
295→            avg_cost_per_plan: 0.0,
296→            avg_input_tokens_per_spawn: 0.0,
297→            n_plans: 0,
298→            n_records: 0,
299→        };
300→    }
301→
302→    // Pass rate over first-attempt records only.
303→    let first: Vec<&TaskMetric> = records.iter().filter(|r| r.iteration == 1).collect();
304→    let pass_rate = if first.is_empty() {
305→        0.0
306→    } else {
307→        first.iter().filter(|r| r.gate_passed).count() as f64 / first.len() as f64
308→    };
309→
310→    // Group by plan_id.
311→    let mut plans: std::collections::BTreeMap<&str, PlanAgg> = std::collections::BTreeMap::new();
312→    for r in records {
313→        let agg = plans.entry(r.plan_id.as_str()).or_default();
314→        agg.max_iter = agg.max_iter.max(r.iteration);
315→        agg.total_cost += r.cost_usd;
316→    }
317→
318→    let n_plans = plans.len();
319→    let avg_iters =
320→        plans.values().map(|a| f64::from(a.max_iter)).sum::<f64>() / n_plans.max(1) as f64;
321→    let avg_cost = plans.values().map(|a| a.total_cost).sum::<f64>() / n_plans.max(1) as f64;
322→
323→    let avg_input =
324→        records.iter().map(|r| r.input_tokens as f64).sum::<f64>() / records.len() as f64;
325→
326→    Headlines {
327→        first_attempt_pass_rate: pass_rate,
328→        avg_iterations_per_plan: avg_iters,
329→        avg_cost_per_plan: avg_cost,
330→        avg_input_tokens_per_spawn: avg_input,
331→        n_plans,
332→        n_records: records.len(),
333→    }
334→}
335→
336→#[derive(Default)]
337→struct PlanAgg {
338→    max_iter: u32,
339→    total_cost: f64,
340→}
