  1→//! Prometheus-flavoured metric primitives (§40.1 + §40.2).
  2→//!
  3→//! This module produces metric strings in the [Prometheus text exposition
  4→//! format](https://prometheus.io/docs/instrumenting/exposition_formats/#text-based-format).
  5→//! It does **not** serve HTTP; embedding binaries (gateway, mirage-rs,
  6→//! roko-cli) call [`MetricRegistry::render_prometheus`] and plug the result
  7→//! into their own axum / hyper route.
  8→//!
  9→//! Manual implementation (no `prometheus` crate dep) keeps roko-core's
 10→//! dependency surface small. The text format is genuinely simple:
 11→//!
 12→//! ```text
 13→//! # HELP name help text
 14→//! # TYPE name counter|gauge|histogram
 15→//! name{label="value",...} number
 16→//! ```
 17→
 18→use std::fmt::Write as _;
 19→use std::sync::Arc;
 20→use std::sync::atomic::{AtomicI64, AtomicU64, Ordering};
 21→
 22→use parking_lot::RwLock;
 23→use serde::{Deserialize, Serialize};
 24→
 25→use crate::obs::histograms::{Histogram, HistogramSnapshot, escape_help, format_f64};
 26→
 27→// ─── Primitives: Counter + Gauge ─────────────────────────────────────
 28→
 29→/// Monotonically increasing `u64` counter. Cheap, lock-free, clonable
 30→/// handle (`Arc` inside).
 31→#[derive(Debug, Clone)]
 32→pub struct Counter {
 33→    inner: Arc<AtomicU64>,
 34→}
 35→
 36→impl Counter {
 37→    /// Construct a new counter initialised to zero.
 38→    #[must_use]
 39→    pub fn new() -> Self {
 40→        Self {
 41→            inner: Arc::new(AtomicU64::new(0)),
 42→        }
 43→    }
 44→
 45→    /// Increment by 1.
 46→    pub fn inc(&self) {
 47→        self.inner.fetch_add(1, Ordering::Relaxed);
 48→    }
 49→
 50→    /// Increment by `n`.
 51→    pub fn inc_by(&self, n: u64) {
 52→        self.inner.fetch_add(n, Ordering::Relaxed);
 53→    }
 54→
 55→    /// Current counter value.
 56→    #[must_use]
 57→    pub fn get(&self) -> u64 {
 58→        self.inner.load(Ordering::Relaxed)
 59→    }
 60→}
 61→
 62→impl Default for Counter {
 63→    fn default() -> Self {
 64→        Self::new()
 65→    }
 66→}
 67→
 68→/// Signed gauge (can go up and down). Stored as `i64` atomics for `add`
 69→/// and `sub`; `set` takes a signed integer.
 70→#[derive(Debug, Clone)]
 71→pub struct Gauge {
 72→    inner: Arc<AtomicI64>,
 73→}
 74→
 75→impl Gauge {
 76→    /// Construct a new gauge initialised to zero.
 77→    #[must_use]
 78→    pub fn new() -> Self {
 79→        Self {
 80→            inner: Arc::new(AtomicI64::new(0)),
 81→        }
 82→    }
 83→
 84→    /// Set the gauge to `v`.
 85→    pub fn set(&self, v: i64) {
 86→        self.inner.store(v, Ordering::Relaxed);
 87→    }
 88→
 89→    /// Add `n` to the gauge.
 90→    pub fn add(&self, n: i64) {
 91→        self.inner.fetch_add(n, Ordering::Relaxed);
 92→    }
 93→
 94→    /// Subtract `n` from the gauge.
 95→    pub fn sub(&self, n: i64) {
 96→        self.inner.fetch_sub(n, Ordering::Relaxed);
 97→    }
 98→
 99→    /// Current gauge value.
100→    #[must_use]
101→    pub fn get(&self) -> i64 {
102→        self.inner.load(Ordering::Relaxed)
103→    }
104→}
105→
106→impl Default for Gauge {
107→    fn default() -> Self {
108→        Self::new()
109→    }
110→}
