112→// ─── LabelSet ────────────────────────────────────────────────────────
113→
114→/// A stable-sorted set of label key/value pairs used for metric identity
115→/// and Prometheus line formatting.
116→///
117→/// Label values are escaped per Prometheus spec (backslash, double-quote,
118→/// newline). Keys are assumed to already be valid Prometheus label names
119→/// (`[a-zA-Z_][a-zA-Z0-9_]*`).
120→#[derive(Debug, Clone, Default, PartialEq, Eq, Hash)]
121→pub struct LabelSet {
122→    pairs: Vec<(&'static str, String)>,
123→}
124→
125→impl LabelSet {
126→    /// Construct an empty label set.
127→    #[must_use]
128→    pub fn new() -> Self {
129→        Self::default()
130→    }
131→
132→    /// Construct from a slice of static-key pairs. Duplicate keys are
133→    /// resolved to the last-supplied value (matching `HashMap` semantics).
134→    #[must_use]
135→    pub fn from_pairs(pairs: &[(&'static str, &str)]) -> Self {
136→        let mut out = Self::new();
137→        for (k, v) in pairs {
138→            out.insert(k, (*v).to_string());
139→        }
140→        out
141→    }
142→
143→    /// Insert / replace a label. Keeps the internal vec stable-sorted.
144→    pub fn insert(&mut self, key: &'static str, value: String) {
145→        if let Some(slot) = self.pairs.iter_mut().find(|(k, _)| *k == key) {
146→            slot.1 = value;
147→        } else {
148→            self.pairs.push((key, value));
149→            self.pairs.sort_by_key(|(k, _)| *k);
150→        }
151→    }
152→
153→    /// Number of labels.
154→    #[must_use]
155→    pub fn len(&self) -> usize {
156→        self.pairs.len()
157→    }
158→
159→    /// True if no labels are registered.
160→    #[must_use]
161→    pub fn is_empty(&self) -> bool {
162→        self.pairs.is_empty()
163→    }
164→
165→    /// Borrow the sorted pairs.
166→    #[must_use]
167→    pub fn pairs(&self) -> &[(&'static str, String)] {
168→        &self.pairs
169→    }
170→
171→    /// Render the inside of the Prometheus label-set (without the
172→    /// enclosing curly braces). Returns an empty string when there are
173→    /// no labels.
174→    #[must_use]
175→    pub fn render_inner(&self) -> String {
176→        let mut out = String::new();
177→        for (i, (k, v)) in self.pairs.iter().enumerate() {
178→            if i > 0 {
179→                out.push(',');
180→            }
181→            out.push_str(k);
182→            out.push_str("=\"");
183→            out.push_str(&escape_label_value(v));
184→            out.push('"');
185→        }
186→        out
187→    }
188→
189→    /// Render as `{k1="v1",k2="v2"}`; empty string if the set is empty.
190→    #[must_use]
191→    pub fn render_braced(&self) -> String {
192→        if self.pairs.is_empty() {
193→            String::new()
194→        } else {
195→            format!("{{{}}}", self.render_inner())
196→        }
197→    }
198→}
199→
200→fn escape_label_value(v: &str) -> String {
201→    let mut out = String::with_capacity(v.len());
202→    for c in v.chars() {
203→        match c {
204→            '\\' => out.push_str("\\\\"),
205→            '"' => out.push_str("\\\""),
206→            '\n' => out.push_str("\\n"),
207→            _ => out.push(c),
208→        }
209→    }
210→    out
211→}
