213→// ─── MetricKind ──────────────────────────────────────────────────────
214→
215→/// The three metric kinds exposed to Prometheus.
216→#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
217→pub enum MetricKind {
218→    /// Monotonically increasing counter.
219→    Counter,
220→    /// Signed up/down gauge.
221→    Gauge,
222→    /// Observation histogram.
223→    Histogram,
224→}
225→
226→impl MetricKind {
227→    const fn type_str(self) -> &'static str {
228→        match self {
229→            Self::Counter => "counter",
230→            Self::Gauge => "gauge",
231→            Self::Histogram => "histogram",
232→        }
233→    }
234→}
