236→// ─── MetricRegistry ──────────────────────────────────────────────────
237→
238→/// A registered metric family (all shapes share `name` + `help`).
239→struct Family {
240→    name: String,
241→    help: String,
242→    kind: MetricKind,
243→    entries: Vec<Entry>,
244→}
245→
246→struct Entry {
247→    labels: LabelSet,
248→    variant: Variant,
249→}
250→
251→enum Variant {
252→    Counter(Counter),
253→    Gauge(Gauge),
254→    Histogram(Arc<Histogram>),
255→}
256→
257→/// Thread-safe metric registry.
258→///
259→/// Registration takes the write-lock; metric mutation is lock-free
260→/// (counters/gauges use atomics, histograms use their own CAS loop).
261→/// `render_prometheus` takes the read-lock.
262→pub struct MetricRegistry {
263→    inner: RwLock<Vec<Family>>,
264→}
265→
266→impl MetricRegistry {
267→    /// Construct an empty registry.
268→    #[must_use]
269→    pub const fn new() -> Self {
270→        Self {
271→            inner: RwLock::new(Vec::new()),
272→        }
273→    }
274→
275→    /// Register or look-up a counter. Idempotent: a second call with the
276→    /// same `(name, labels)` returns a handle to the existing counter.
277→    /// `help` from the first registration wins.
278→    pub fn register_counter(&self, name: &str, help: &str, labels: LabelSet) -> Counter {
279→        let mut families = self.inner.write();
280→        let family = get_or_insert_family(&mut families, name, help, MetricKind::Counter);
281→        for entry in &family.entries {
282→            if entry.labels == labels {
283→                if let Variant::Counter(c) = &entry.variant {
284→                    let handle = c.clone();
285→                    drop(families);
286→                    return handle;
287→                }
288→            }
289→        }
290→        let c = Counter::new();
291→        family.entries.push(Entry {
292→            labels,
293→            variant: Variant::Counter(c.clone()),
294→        });
295→        drop(families);
296→        c
297→    }
298→
299→    /// Register or look-up a gauge. Same idempotence contract as
300→    /// [`Self::register_counter`].
301→    pub fn register_gauge(&self, name: &str, help: &str, labels: LabelSet) -> Gauge {
302→        let mut families = self.inner.write();
303→        let family = get_or_insert_family(&mut families, name, help, MetricKind::Gauge);
304→        for entry in &family.entries {
305→            if entry.labels == labels {
306→                if let Variant::Gauge(g) = &entry.variant {
307→                    let handle = g.clone();
308→                    drop(families);
309→                    return handle;
310→                }
311→            }
312→        }
313→        let g = Gauge::new();
314→        family.entries.push(Entry {
315→            labels,
316→            variant: Variant::Gauge(g.clone()),
317→        });
318→        drop(families);
319→        g
320→    }
321→
322→    /// Register or look-up a histogram.
323→    ///
324→    /// If an existing histogram with the same `(name, labels)` is found,
325→    /// the supplied `buckets` argument is ignored — the original boundaries
326→    /// win. This matches the Prometheus client-library contract.
327→    pub fn register_histogram(
328→        &self,
329→        name: &str,
330→        help: &str,
331→        labels: LabelSet,
332→        buckets: Vec<f64>,
333→    ) -> Arc<Histogram> {
334→        let mut families = self.inner.write();
335→        let family = get_or_insert_family(&mut families, name, help, MetricKind::Histogram);
336→        for entry in &family.entries {
337→            if entry.labels == labels {
338→                if let Variant::Histogram(h) = &entry.variant {
339→                    let handle = Arc::clone(h);
340→                    drop(families);
341→                    return handle;
342→                }
343→            }
344→        }
345→        let h = Arc::new(Histogram::new(buckets));
346→        family.entries.push(Entry {
347→            labels,
348→            variant: Variant::Histogram(Arc::clone(&h)),
349→        });
350→        drop(families);
351→        h
352→    }
353→
354→    /// Look up an existing counter without registering.
355→    #[must_use]
356→    pub fn get_counter(&self, name: &str, labels: &LabelSet) -> Option<Counter> {
357→        let families = self.inner.read();
358→        let mut out = None;
359→        for family in families.iter() {
360→            if family.name == name && family.kind == MetricKind::Counter {
361→                for entry in &family.entries {
362→                    if &entry.labels == labels {
363→                        if let Variant::Counter(c) = &entry.variant {
364→                            out = Some(c.clone());
365→                            break;
366→                        }
367→                    }
368→                }
369→            }
370→        }
371→        drop(families);
372→        out
373→    }
374→
375→    /// Look up an existing gauge without registering.
376→    #[must_use]
377→    pub fn get_gauge(&self, name: &str, labels: &LabelSet) -> Option<Gauge> {
378→        let families = self.inner.read();
379→        let mut out = None;
380→        for family in families.iter() {
381→            if family.name == name && family.kind == MetricKind::Gauge {
382→                for entry in &family.entries {
383→                    if &entry.labels == labels {
384→                        if let Variant::Gauge(g) = &entry.variant {
385→                            out = Some(g.clone());
386→                            break;
387→                        }
388→                    }
389→                }
390→            }
391→        }
392→        drop(families);
393→        out
394→    }
395→
396→    /// Look up an existing histogram without registering.
397→    #[must_use]
398→    pub fn get_histogram(&self, name: &str, labels: &LabelSet) -> Option<Arc<Histogram>> {
399→        let families = self.inner.read();
400→        let mut out = None;
401→        for family in families.iter() {
402→            if family.name == name && family.kind == MetricKind::Histogram {
403→                for entry in &family.entries {
404→                    if &entry.labels == labels {
405→                        if let Variant::Histogram(h) = &entry.variant {
406→                            out = Some(Arc::clone(h));
407→                            break;
408→                        }
409→                    }
410→                }
411→            }
412→        }
413→        drop(families);
414→        out
415→    }
416→
417→    /// Number of registered metric families.
418→    #[must_use]
419→    pub fn family_count(&self) -> usize {
420→        let families = self.inner.read();
421→        let n = families.len();
422→        drop(families);
423→        n
424→    }
425→
426→    /// Render the entire registry in Prometheus text-exposition format.
427→    ///
428→    /// Output groups every family under a single `# HELP` / `# TYPE`
429→    /// pair and emits one line per (family, labels) entry.
430→    #[must_use]
431→    pub fn render_prometheus(&self) -> String {
432→        let families = self.inner.read();
433→        let mut out = String::new();
434→        for family in families.iter() {
435→            let _ = writeln!(out, "# HELP {} {}", family.name, escape_help(&family.help));
436→            let _ = writeln!(out, "# TYPE {} {}", family.name, family.kind.type_str());
437→            for entry in &family.entries {
438→                match &entry.variant {
439→                    Variant::Counter(c) => {
440→                        let lbl = entry.labels.render_braced();
441→                        let _ = writeln!(out, "{}{lbl} {}", family.name, c.get());
442→                    }
443→                    Variant::Gauge(g) => {
444→                        let lbl = entry.labels.render_braced();
445→                        let _ = writeln!(out, "{}{lbl} {}", family.name, g.get());
446→                    }
447→                    Variant::Histogram(h) => {
448→                        out.push_str(&render_histogram_lines(&family.name, h, &entry.labels));
449→                    }
450→                }
451→            }
452→        }
453→        drop(families);
454→        out
455→    }
456→
457→    /// Serialize every metric as a [`MetricSnapshot`] list (JSON-friendly).
458→    #[must_use]
459→    pub fn snapshot(&self) -> Vec<MetricSnapshot> {
460→        let families = self.inner.read();
461→        let mut out = Vec::new();
462→        for family in families.iter() {
463→            for entry in &family.entries {
464→                let value = match &entry.variant {
465→                    Variant::Counter(c) => MetricValue::Counter(c.get()),
466→                    Variant::Gauge(g) => MetricValue::Gauge(g.get()),
467→                    Variant::Histogram(h) => MetricValue::Histogram(h.snapshot()),
468→                };
469→                out.push(MetricSnapshot {
470→                    name: family.name.clone(),
471→                    help: family.help.clone(),
472→                    kind: family.kind,
473→                    labels: entry
474→                        .labels
475→                        .pairs()
476→                        .iter()
477→                        .map(|(k, v)| ((*k).to_string(), v.clone()))
478→                        .collect(),
479→                    value,
480→                });
481→            }
482→        }
483→        drop(families);
484→        out
485→    }
486→}
487→
488→impl Default for MetricRegistry {
489→    fn default() -> Self {
490→        Self::new()
491→    }
492→}
493→
494→fn get_or_insert_family<'a>(
495→    families: &'a mut Vec<Family>,
496→    name: &str,
497→    help: &str,
498→    kind: MetricKind,
499→) -> &'a mut Family {
500→    // Find-or-push; index-based so we can return a borrow that covers
501→    // both branches without lifetime juggling.
502→    let idx = families
503→        .iter()
504→        .position(|f| f.name == name)
505→        .unwrap_or_else(|| {
506→            families.push(Family {
507→                name: name.to_string(),
508→                help: help.to_string(),
509→                kind,
510→                entries: Vec::new(),
511→            });
512→            families.len() - 1
513→        });
514→    &mut families[idx]
515→}
516→
517→fn render_histogram_lines(name: &str, h: &Histogram, labels: &LabelSet) -> String {
518→    let snap = h.snapshot();
519→    let base = labels.render_inner();
520→    let sep = if base.is_empty() { "" } else { "," };
521→    let mut out = String::new();
522→    for (upper, cum) in snap.buckets.iter().zip(snap.counts.iter()) {
523→        let _ = writeln!(
524→            out,
525→            "{name}_bucket{{{base}{sep}le=\"{}\"}} {cum}",
526→            format_f64(*upper),
527→        );
528→    }
529→    let inf_cum = snap.counts.last().copied().unwrap_or(0);
530→    let _ = writeln!(out, "{name}_bucket{{{base}{sep}le=\"+Inf\"}} {inf_cum}");
531→    if base.is_empty() {
532→        let _ = writeln!(out, "{name}_sum {}", format_f64(snap.sum));
533→        let _ = writeln!(out, "{name}_count {}", snap.count);
534→    } else {
535→        let _ = writeln!(out, "{name}_sum{{{base}}} {}", format_f64(snap.sum));
536→        let _ = writeln!(out, "{name}_count{{{base}}} {}", snap.count);
537→    }
538→    out
539→}
