541→// ─── Snapshot (JSON-friendly) ────────────────────────────────────────
542→
543→/// JSON-friendly view of one metric entry.
544→#[derive(Debug, Clone, Serialize, Deserialize)]
545→pub struct MetricSnapshot {
546→    /// Metric family name.
547→    pub name: String,
548→    /// Free-form help text.
549→    pub help: String,
550→    /// Family kind.
551→    pub kind: MetricKind,
552→    /// Label pairs (sorted).
553→    pub labels: Vec<(String, String)>,
554→    /// The current value.
555→    pub value: MetricValue,
556→}
557→
558→/// The typed value carried by a [`MetricSnapshot`].
559→///
560→/// Serialised with an internal `type` tag so downstream consumers can
561→/// switch on `value.type`. (A `tag = ...` on a newtype variant holding a
562→/// scalar is not supported by serde; we use adjacent tagging instead.)
563→#[derive(Debug, Clone, Serialize, Deserialize)]
564→#[serde(tag = "type", content = "value", rename_all = "snake_case")]
565→pub enum MetricValue {
566→    /// Counter observation.
567→    Counter(u64),
568→    /// Gauge observation.
569→    Gauge(i64),
570→    /// Histogram snapshot.
571→    Histogram(HistogramSnapshot),
572→}
