574→// ─── Standard metric catalog (§40.2) ─────────────────────────────────
575→
576→/// The seven standard metrics every Roko binary registers (§40.2).
577→///
578→/// Format: `(name, help, kind)`. Label keys are documented in comments
579→/// below; they are not encoded here because label values are only known
580→/// at emit time (e.g. `status=succeeded`, `role=coder`).
581→pub const STANDARD_METRICS: &[(&str, &str, MetricKind)] = &[
582→    // labels: status
583→    (
584→        "roko_plans_total",
585→        "Total number of plans observed, by status",
586→        MetricKind::Counter,
587→    ),
588→    // labels: status, role
589→    (
590→        "roko_tasks_total",
591→        "Total number of tasks observed, by status and role",
592→        MetricKind::Counter,
593→    ),
594→    // labels: tool, outcome
595→    (
596→        "roko_tool_calls_total",
597→        "Total tool calls, by tool and outcome",
598→        MetricKind::Counter,
599→    ),
600→    // labels: gate, verdict
601→    (
602→        "roko_gate_verdicts_total",
603→        "Gate verdicts, by gate and verdict",
604→        MetricKind::Counter,
605→    ),
606→    // labels: backend, role
607→    (
608→        "roko_agent_duration_seconds",
609→        "Agent turn duration in seconds, by backend and role",
610→        MetricKind::Histogram,
611→    ),
612→    // labels: provider, model, direction (input|output|cached)
613→    (
614→        "roko_llm_tokens_total",
615→        "LLM tokens consumed/produced, by provider, model, direction",
616→        MetricKind::Counter,
617→    ),
618→    // labels: provider, model
619→    (
620→        "roko_llm_cost_usd_total",
621→        "Cumulative LLM spend in USD, by provider and model",
622→        MetricKind::Counter,
623→    ),
624→];
625→
626→/// Pre-register every metric in [`STANDARD_METRICS`] with zero labels.
627→///
628→/// This gives callers stable handles they can look up via
629→/// [`MetricRegistry::get_counter`] / [`MetricRegistry::get_histogram`].
630→/// Callers that need labels (e.g. `status="running"`) should call
631→/// `register_counter` directly with the appropriate [`LabelSet`] — the
632→/// family already exists at that point and the registration becomes a
633→/// pure look-up.
634→pub fn register_standard_metrics(registry: &MetricRegistry) {
635→    use crate::obs::histograms::LLM_LATENCY_BUCKETS;
636→    for (name, help, kind) in STANDARD_METRICS {
637→        match kind {
638→            MetricKind::Counter => {
639→                let _ = registry.register_counter(name, help, LabelSet::new());
640→            }
641→            MetricKind::Gauge => {
642→                let _ = registry.register_gauge(name, help, LabelSet::new());
643→            }
644→            MetricKind::Histogram => {
645→                let _ = registry.register_histogram(
646→                    name,
647→                    help,
648→                    LabelSet::new(),
649→                    LLM_LATENCY_BUCKETS.to_vec(),
650→                );
651→            }
652→        }
653→    }
654→}
