873→        let handles: Vec<_> = (0u64..4)
874→            .map(|i| {
875→                let reg = StdArc::clone(&reg);
876→                std::thread::spawn(move || {
877→                    let labels = LabelSet::from_pairs(&[("status", "ok")]);
878→                    let c = reg.register_counter("x_total", "x", labels);
879→                    c.inc_by(i + 1);
880→                })
881→            })
882→            .collect();
883→        for h in handles {
884→            h.join().expect("thread joined");
885→        }
886→        // All 4 threads share one counter: 1+2+3+4 = 10
887→        let c = reg
888→            .get_counter("x_total", &LabelSet::from_pairs(&[("status", "ok")]))
889→            .expect("counter registered by threads");
890→        assert_eq!(c.get(), 10);
891→    }
892→}
