  1→//! Operating frequency bands for 3-speed cognition.
  2→//!
  3→//! These frequencies name the intended cadence of agent behavior:
  4→//! - `Gamma`: reactive, ~10s
  5→//! - `Theta`: strategic, ~2-5min
  6→//! - `Delta`: consolidation, ~30min+
  7→
  8→use crate::{Task, TaskContextWeight, TaskQualityProfile, TaskReasoningLevel};
  9→use bardo_primitives::tier::InferenceTier;
 10→use serde::{Deserialize, Serialize};
 11→use std::time::Duration;
 12→
 13→/// Cognitive operating frequency for agent work.
 14→#[derive(Clone, Copy, Debug, Eq, Ord, PartialEq, PartialOrd, Hash, Serialize, Deserialize)]
 15→#[serde(rename_all = "snake_case")]
 16→pub enum OperatingFrequency {
 17→    /// Reactive mode: perceive, retrieve, act.
 18→    ///
 19→    /// Tool calls, cache lookups, and signal routing.
 20→    Gamma,
 21→    /// Strategic mode: re-plan, update goals, evaluate progress.
 22→    ///
 23→    /// Periodic step-back / course-correction passes.
 24→    Theta,
 25→    /// Consolidation mode: replay, distill, meta-cognate.
 26→    ///
 27→    /// Slow learning and knowledge consolidation.
 28→    Delta,
 29→}
 30→
 31→impl OperatingFrequency {
 32→    /// Map to the existing inference tier model.
 33→    #[must_use]
 34→    pub const fn inference_tier(self) -> InferenceTier {
 35→        match self {
 36→            Self::Gamma => InferenceTier::T0,
 37→            Self::Theta => InferenceTier::T1,
 38→            Self::Delta => InferenceTier::T2,
 39→        }
 40→    }
 41→
 42→    /// Map operating frequency to the default agent turn limit.
 43→    ///
 44→    /// - `Gamma` reactive work does not dispatch an agent.
 45→    /// - `Theta` deliberative work uses the default 20-turn budget.
 46→    /// - `Delta` reflective work gets a 50-turn budget.
 47→    #[must_use]
 48→    pub const fn turn_limit(self) -> u32 {
 49→        match self {
 50→            Self::Gamma => 0,
 51→            Self::Theta => 20,
 52→            Self::Delta => 50,
 53→        }
 54→    }
 55→
 56→    /// Select the operating frequency for a task and its current affect state.
 57→    ///
 58→    /// Rules:
 59→    /// - `Gamma` for reactive work like `quick_fix`, gate re-checks, permission checks,
 60→    ///   and subscription-filter evaluation.
 61→    /// - `Delta` for reflective work like dream cycles, plan regeneration, and retrospectives.
 62→    /// - `Theta` for the default deliberative path.
 63→    /// - Low-confidence, substantial tasks are promoted to `Delta` so the loop can step back
 64→    ///   and reconsider the approach instead of blindly continuing.
 65→    #[must_use]
 66→    pub fn select(task: &Task, affect: &impl OperatingFrequencyAffect) -> Self {
 67→        if is_reactive_task(task) {
 68→            return Self::Gamma;
 69→        }
 70→
 71→        if is_reflective_task(task) {
 72→            return Self::Delta;
 73→        }
 74→
 75→        if affect_suggests_reflection(affect) && task.is_substantial() {
 76→            return Self::Delta;
 77→        }
 78→
 79→        Self::Theta
 80→    }
 81→}
 82→
 83→/// Runtime inputs used by the operating-frequency scheduler.
 84→///
 85→/// This is intentionally small and pure: the scheduler only needs timing,
 86→/// throughput, and affect signals to choose the next loop.
 87→#[derive(Clone, Copy, Debug, PartialEq)]
 88→pub struct OperatingFrequencyScheduleContext {
 89→    /// Time elapsed since the last theta evaluation.
 90→    pub time_since_last_theta: Duration,
 91→    /// Number of currently active tasks.
 92→    pub active_tasks: usize,
 93→    /// Recent task completion rate in `[0.0, 1.0]`.
 94→    pub completion_rate: f64,
 95→    /// Motivational confidence in `[0.0, 1.0]`.
 96→    pub confidence: f64,
 97→    /// Arousal in `[-1.0, 1.0]`.
 98→    pub arousal: f64,
 99→    /// Dominance in `[-1.0, 1.0]`.
100→    pub dominance: f64,
101→}
102→
103→impl OperatingFrequencyScheduleContext {
104→    /// Construct a scheduling context from a read-only affect view.
105→    #[must_use]
106→    pub fn from_affect(
107→        time_since_last_theta: Duration,
108→        active_tasks: usize,
109→        completion_rate: f64,
110→        affect: &impl OperatingFrequencyAffect,
111→    ) -> Self {
112→        Self {
113→            time_since_last_theta,
114→            active_tasks,
115→            completion_rate,
116→            confidence: affect.confidence(),
117→            arousal: affect.arousal(),
118→            dominance: affect.dominance(),
119→        }
120→    }
121→
122→    /// Returns `true` when the system has no active tasks.
123→    #[must_use]
124→    pub const fn is_idle(self) -> bool {
125→        self.active_tasks == 0
126→    }
127→
128→    /// Returns `true` when work is stalling.
129→    #[must_use]
130→    pub fn is_stalling(self) -> bool {
131→        self.completion_rate <= STALLING_COMPLETION_RATE_THRESHOLD
132→    }
133→
134→    /// Returns `true` when affect suggests the loop should step back sooner.
135→    #[must_use]
136→    pub fn is_anxious(self) -> bool {
137→        self.confidence <= ANXIOUS_CONFIDENCE_THRESHOLD
138→            && self.arousal >= ANXIOUS_AROUSAL_THRESHOLD
139→            && self.dominance <= ANXIOUS_DOMINANCE_THRESHOLD
140→    }
141→}
142→
143→/// Selects the next operating frequency from runtime context.
144→///
145→/// - Idle systems consolidate with `Delta`.
146→/// - Stalling or anxious systems shorten the theta cadence.
147→/// - Otherwise the scheduler stays in `Gamma` until theta becomes due.
148→#[derive(Clone, Copy, Debug, PartialEq)]
149→pub struct OperatingFrequencyScheduler {
150→    theta_interval: Duration,
151→    delta_interval: Duration,
152→}
153→
154→impl Default for OperatingFrequencyScheduler {
155→    fn default() -> Self {
156→        Self::new()
157→    }
158→}
159→
160→impl OperatingFrequencyScheduler {
161→    /// Default scheduler:
162→    /// - theta every 3 minutes
163→    /// - delta every 30 minutes
164→    #[must_use]
165→    pub fn new() -> Self {
166→        Self {
167→            theta_interval: Duration::from_secs(180),
168→            delta_interval: Duration::from_secs(30 * 60),
169→        }
170→    }
171→
172→    /// Override the base theta interval.
173→    #[must_use]
174→    pub fn with_theta_interval(mut self, theta_interval: Duration) -> Self {
175→        assert!(
176→            theta_interval > Duration::ZERO,
177→            "theta interval must be positive"
178→        );
179→        self.theta_interval = theta_interval;
180→        self
181→    }
182→
183→    /// Override the delta consolidation interval.
184→    #[must_use]
185→    pub fn with_delta_interval(mut self, delta_interval: Duration) -> Self {
186→        assert!(
187→            delta_interval > Duration::ZERO,
188→            "delta interval must be positive"
189→        );
190→        self.delta_interval = delta_interval;
191→        self
192→    }
193→
194→    /// Choose the next loop to run.
195→    #[must_use]
196→    pub fn select(&self, context: &OperatingFrequencyScheduleContext) -> OperatingFrequency {
197→        if context.is_idle() {
198→            return OperatingFrequency::Delta;
199→        }
200→
201→        if context.time_since_last_theta >= self.delta_interval {
202→            return OperatingFrequency::Delta;
203→        }
204→
205→        let theta_due = self.theta_interval_for(context);
206→        if context.time_since_last_theta >= theta_due {
207→            OperatingFrequency::Theta
208→        } else {
209→            OperatingFrequency::Gamma
210→        }
211→    }
212→
213→    fn theta_interval_for(&self, context: &OperatingFrequencyScheduleContext) -> Duration {
214→        let mut factor = 1.0;
215→
216→        if context.is_stalling() {
217→            factor *= STALLING_THETA_MULTIPLIER;
218→        }
219→
220→        if context.is_anxious() {
221→            factor *= ANXIOUS_THETA_MULTIPLIER;
222→        }
223→
224→        scale_duration(self.theta_interval, factor)
225→    }
226→}
227→
228→/// Read-only affect view used by frequency selection.
229→pub trait OperatingFrequencyAffect {
230→    /// Motivational confidence in `[0.0, 1.0]`.
231→    fn confidence(&self) -> f64;
232→    /// Arousal in `[-1.0, 1.0]`.
233→    fn arousal(&self) -> f64;
234→    /// Dominance in `[-1.0, 1.0]`.
235→    fn dominance(&self) -> f64;
236→}
