238→const LOW_CONFIDENCE_THRESHOLD: f64 = 0.3;
239→const STALLING_COMPLETION_RATE_THRESHOLD: f64 = 0.25;
240→const ANXIOUS_CONFIDENCE_THRESHOLD: f64 = 0.35;
241→const ANXIOUS_AROUSAL_THRESHOLD: f64 = 0.25;
242→const ANXIOUS_DOMINANCE_THRESHOLD: f64 = -0.1;
243→const STALLING_THETA_MULTIPLIER: f64 = 0.5;
244→const ANXIOUS_THETA_MULTIPLIER: f64 = 0.66;
