246→impl Task {
247→    /// Return `true` when the task is large enough to justify a reflective step-back.
248→    #[must_use]
249→    pub fn is_substantial(&self) -> bool {
250→        self.estimated_minutes.is_some_and(|minutes| minutes >= 30)
251→            || matches!(self.reasoning_level, Some(TaskReasoningLevel::High))
252→            || matches!(self.context_weight, Some(TaskContextWeight::Deep))
253→            || matches!(self.quality_profile, Some(TaskQualityProfile::Hardened))
