304→fn task_tag_matches(task: &Task, needle: &str) -> bool {
305→    let normalized_needle = normalize_token(needle);
306→    task.tags.as_deref().is_some_and(|tags| {
307→        tags.iter()
308→            .any(|tag| normalize_token(tag) == normalized_needle)
309→    })
