312→fn task_haystack(task: &Task) -> String {
313→    let mut parts = Vec::new();
314→    parts.push(task.title.to_ascii_lowercase());
315→    if let Some(role) = &task.role {
316→        parts.push(role.to_ascii_lowercase());
317→    }
318→    if let Some(category) = task.category {
319→        parts.push(category.label().to_string());
320→    }
321→    if let Some(tags) = &task.tags {
322→        parts.extend(tags.iter().map(|tag| tag.to_ascii_lowercase()));
323→    }
324→    parts.push(task.id.to_ascii_lowercase());
325→    parts.join(" ")
326→}
