## 7. Rust Struct Designs for Dual-Process Validation Tracking

These are designed to integrate with roko's existing types: `ModelTier`, `TaskComplexityBand`, `CascadeStage`, `RoutingDecisionLog`.

```rust
use chrono::{DateTime, Utc};
use serde::{Deserialize, Serialize};
use roko_core::agent::ModelTier;
use roko_core::task::TaskComplexityBand;

// ─── Gating Accuracy Tracking ────────────────────────────────────────────────

/// Ground truth for a single routing decision, recorded after task completion.
///
/// A decision is "correct" if the assigned tier succeeded without escalation
/// AND no lower tier could have handled the same query (i.e., no over-provision).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GatingOutcome {
    /// Task or query identifier.
    pub task_id: String,
    /// The tier the router assigned.
    pub assigned_tier: ModelTier,
    /// The tier that actually handled the task (may differ if escalation occurred).
    pub final_tier: ModelTier,
    /// Whether the task succeeded at `final_tier`.
    pub succeeded: bool,
    /// Whether escalation was triggered (assigned != final).
    pub escalated: bool,
    /// Estimated minimum tier that could have succeeded (post-hoc oracle).
    /// `None` if unknown.
    pub oracle_tier: Option<ModelTier>,
    /// Confidence score the router reported at assignment time (0.0–1.0).
    pub gate_confidence: f32,
    /// Actual cost incurred in USD.
    pub cost_usd: f32,
    /// Timestamp.
    pub at: DateTime<Utc>,
}

impl GatingOutcome {
    /// True positive: assigned Fast/Standard and it succeeded without escalation.
    pub fn is_tp(&self) -> bool {
        !self.escalated && self.succeeded
    }

    /// False positive: assigned a cheap tier, but had to escalate.
    pub fn is_fp(&self) -> bool {
        self.escalated
    }

    /// False negative: assigned Premium, but oracle says cheaper would have worked.
    pub fn is_fn(&self) -> bool {
        matches!(
            (&self.assigned_tier, &self.oracle_tier),
            (ModelTier::Premium, Some(t)) if *t != ModelTier::Premium
        )
    }
}

// ─── Aggregate Gating Metrics ─────────────────────────────────────────────────

/// Rolling precision/recall/F1 for tier suppression decisions.
///
/// "Suppression" = assigning a query to Fast or Standard rather than Premium.
/// Precision: what fraction of suppression decisions were correct (no escalation).
/// Recall: what fraction of query that could be suppressed were actually suppressed.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct GatingAccuracyMetrics {
    /// Window size (number of recent decisions included).
    pub window: usize,
    /// True positives in window.
    pub tp: u64,
    /// False positives in window (unnecessary escalations).
    pub fp: u64,
    /// False negatives in window (over-provisioned to Premium).
    pub fn_count: u64,
    /// True negatives (Premium assigned, Premium needed, no cheaper option).
    pub tn: u64,
    /// Computed precision: TP / (TP + FP). `None` if denominator is 0.
    pub precision: Option<f32>,
    /// Computed recall: TP / (TP + FN). `None` if denominator is 0.
    pub recall: Option<f32>,
    /// F1 = 2 * P * R / (P + R). `None` if undefined.
    pub f1: Option<f32>,
    /// Escalation rate: FP / (TP + FP). Target < 0.10.
    pub escalation_rate: Option<f32>,
    /// Over-provision rate: FN / (TP + TN + FP + FN). Target < 0.15.
    pub over_provision_rate: Option<f32>,
    /// Timestamp of computation.
    pub computed_at: DateTime<Utc>,
}

impl GatingAccuracyMetrics {
    pub fn compute(outcomes: &[GatingOutcome]) -> Self {
        let tp = outcomes.iter().filter(|o| o.is_tp()).count() as u64;
        let fp = outcomes.iter().filter(|o| o.is_fp()).count() as u64;
        let fn_count = outcomes.iter().filter(|o| o.is_fn()).count() as u64;
        let tn = outcomes.len() as u64 - tp - fp - fn_count;

        let precision = if tp + fp > 0 {
            Some(tp as f32 / (tp + fp) as f32)
        } else {
            None
        };
        let recall = if tp + fn_count > 0 {
            Some(tp as f32 / (tp + fn_count) as f32)
        } else {
            None
        };
        let f1 = match (precision, recall) {
            (Some(p), Some(r)) if p + r > 0.0 => Some(2.0 * p * r / (p + r)),
            _ => None,
        };
        let escalation_rate = if tp + fp > 0 {
            Some(fp as f32 / (tp + fp) as f32)
        } else {
            None
        };
        let total = outcomes.len() as u64;
        let over_provision_rate = if total > 0 {
            Some(fn_count as f32 / total as f32)
        } else {
            None
        };

        Self {
            window: outcomes.len(),
            tp, fp, fn_count, tn,
            precision, recall, f1,
            escalation_rate, over_provision_rate,
            computed_at: Utc::now(),
        }
    }
}

// ─── Calibration Tracking (ECE) ───────────────────────────────────────────────

/// One bin in an Expected Calibration Error (ECE) reliability diagram.
///
/// Confidence range [lo, hi). Tracks mean confidence and actual accuracy in bin.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CalibrationBin {
    /// Lower bound of confidence range (inclusive).
    pub lo: f32,
    /// Upper bound of confidence range (exclusive).
    pub hi: f32,
    /// Number of samples in this bin.
    pub count: u64,
    /// Mean predicted confidence in this bin.
    pub mean_confidence: f32,
    /// Empirical accuracy (fraction that actually succeeded) in this bin.
    pub empirical_accuracy: f32,
    /// |mean_confidence - empirical_accuracy| — per-bin calibration error.
    pub calibration_error: f32,
}

/// Expected Calibration Error across all confidence bins.
///
/// ECE = Σ_b (|B_b| / n) * |mean_conf(B_b) - acc(B_b)|
/// Target ECE < 0.05 for a well-calibrated gate.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CalibrationReport {
    /// Number of equal-width bins (default 10).
    pub n_bins: usize,
    /// Individual bins.
    pub bins: Vec<CalibrationBin>,
    /// Weighted ECE across all bins.
    pub ece: f32,
    /// Maximum calibration error across any bin (MCE).
    pub mce: f32,
    /// Total samples used.
    pub total_samples: u64,
    /// Timestamp.
    pub computed_at: DateTime<Utc>,
}

impl CalibrationReport {
    /// Compute ECE from a slice of (confidence, success) pairs.
    pub fn compute(samples: &[(f32, bool)], n_bins: usize) -> Self {
        let n = samples.len() as u64;
        let bin_width = 1.0 / n_bins as f32;
        let mut bins = Vec::with_capacity(n_bins);

        for i in 0..n_bins {
            let lo = i as f32 * bin_width;
            let hi = lo + bin_width;
            let in_bin: Vec<_> = samples
                .iter()
                .filter(|(c, _)| *c >= lo && (*c < hi || (i == n_bins - 1 && *c <= 1.0)))
                .collect();
            if in_bin.is_empty() {
                continue;
            }
            let mean_confidence = in_bin.iter().map(|(c, _)| *c).sum::<f32>() / in_bin.len() as f32;
            let empirical_accuracy = in_bin.iter().filter(|(_, ok)| *ok).count() as f32 / in_bin.len() as f32;
            let calibration_error = (mean_confidence - empirical_accuracy).abs();
            bins.push(CalibrationBin {
                lo, hi,
                count: in_bin.len() as u64,
                mean_confidence,
                empirical_accuracy,
                calibration_error,
            });
        }

        let ece = bins.iter().map(|b| (b.count as f32 / n as f32) * b.calibration_error).sum();
        let mce = bins.iter().map(|b| b.calibration_error).fold(0.0_f32, f32::max);

        Self {
            n_bins,
            bins,
            ece,
            mce,
            total_samples: n,
            computed_at: Utc::now(),
        }
    }
}

