## 9. Rust Pseudocode: Phase-Locked Loop for Agent Tick Synchronization

```rust
use std::time::{Duration, Instant};
use std::f64::consts::TAU;

/// A software phase-locked loop that adjusts an agent's tick frequency
/// to synchronize with external event timestamps.
#[derive(Debug)]
pub struct PhaseLockedLoop {
    // Current phase [0, 2π)
    phase: f64,
    // Current angular frequency (rad/s) — the VCO state
    omega: f64,
    // Free-running (natural) frequency (rad/s)
    omega_free: f64,
    // Proportional gain (phase error → frequency correction)
    k_p: f64,
    // Integral gain (accumulated phase error → frequency correction)
    k_i: f64,
    // Accumulated integral term (anti-windup clamped)
    integral: f64,
    // Previous phase error for derivative/proportional difference
    prev_error: f64,
    // Last tick timestamp
    last_tick: Instant,
    // Period estimate (seconds) — adapts via integral
    period_estimate: f64,
}

impl PhaseLockedLoop {
    pub fn new(natural_period_secs: f64, k_p: f64, k_i: f64) -> Self {
        let omega_free = TAU / natural_period_secs;
        Self {
            phase: 0.0,
            omega: omega_free,
            omega_free,
            k_p,
            k_i,
            integral: 0.0,
            prev_error: 0.0,
            last_tick: Instant::now(),
            period_estimate: natural_period_secs,
        }
    }

    /// Advance internal phase by elapsed time.
    /// Call this on every tick, before checking for external events.
    pub fn tick(&mut self) -> f64 {
        let now = Instant::now();
        let dt = now.duration_since(self.last_tick).as_secs_f64();
        self.last_tick = now;

        // VCO: integrate current frequency to advance phase
        self.phase = (self.phase + self.omega * dt) % TAU;
        self.phase
    }

    /// Called when an external event arrives.
    /// `event_target_phase` is the expected phase at which this event should arrive (e.g. 0.0).
    /// Returns the phase correction applied.
    pub fn on_external_event(&mut self, event_target_phase: f64) -> f64 {
        // Phase error: signed angular difference [-π, π]
        let raw_error = event_target_phase - self.phase;
        let phase_error = wrap_to_pi(raw_error);

        // Proportional correction to omega
        let p_correction = self.k_p * phase_error;

        // Integral correction (accumulate frequency bias)
        self.integral = (self.integral + self.k_i * phase_error)
            .clamp(-TAU, TAU); // anti-windup

        // Adjust VCO frequency
        self.omega = self.omega_free + p_correction + self.integral;

        // Update period estimate from current omega
        if self.omega > 0.0 {
            self.period_estimate = TAU / self.omega;
        }

        // Phase-pull: directly nudge phase toward target (type II PRC behavior)
        let alpha = 0.3; // phase coupling gain [0, 1]
        self.phase = (self.phase + alpha * phase_error + TAU) % TAU;

        self.prev_error = phase_error;
        phase_error
    }

    /// Returns estimated time until next cycle boundary.
    pub fn time_until_next_cycle(&self) -> Duration {
        let phase_remaining = TAU - self.phase;
        let time_secs = phase_remaining / self.omega.max(1e-9);
        Duration::from_secs_f64(time_secs)
    }

    /// Current synchrony: 1.0 = perfectly locked, 0.0 = drifting
    pub fn lock_quality(&self) -> f64 {
        let error_fraction = self.prev_error.abs() / TAU;
        (1.0 - error_fraction).max(0.0)
    }

    pub fn period_secs(&self) -> f64 {
        self.period_estimate
    }
}

fn wrap_to_pi(angle: f64) -> f64 {
    use std::f64::consts::PI;
    let mut a = angle % TAU;
    if a > PI { a -= TAU; }
    if a < -PI { a += TAU; }
    a
}
```

### Multi-Agent Fleet Synchronization

```rust
/// Coordinator that broadcasts phase correction signals to a fleet of agents.
/// Implements a "pacemaker" pattern: one agent acts as the reference clock.
pub struct FleetPhaseCoordinator {
    /// Reference PLL (the pacemaker agent)
    pacemaker: PhaseLockedLoop,
    /// Coupling strength K for fleet-level Kuramoto synchronization
    coupling_k: f64,
    /// Phases of follower agents (in a real system, received over network)
    follower_phases: Vec<f64>,
}

impl FleetPhaseCoordinator {
    /// Compute Kuramoto-style correction for a single follower.
    /// `own_phase`: follower's current phase
    /// `all_phases`: all agent phases (including own)
    /// Returns delta_omega to add to follower's natural frequency.
    pub fn kuramoto_correction(&self, own_phase: f64, all_phases: &[f64]) -> f64 {
        let n = all_phases.len() as f64;
        let coupling_sum: f64 = all_phases.iter()
            .map(|&peer_phase| (peer_phase - own_phase).sin())
            .sum();
        (self.coupling_k / n) * coupling_sum
    }

    /// Mean-field phase (psi) and order parameter (r) from all agent phases.
    pub fn order_parameter(&self, phases: &[f64]) -> (f64, f64) {
        let n = phases.len() as f64;
        let sum_cos: f64 = phases.iter().map(|&p| p.cos()).sum::<f64>() / n;
        let sum_sin: f64 = phases.iter().map(|&p| p.sin()).sum::<f64>() / n;
        let r = (sum_cos * sum_cos + sum_sin * sum_sin).sqrt();
        let psi = sum_sin.atan2(sum_cos);
        (r, psi)
    }
}
```

